// ─── Inbound reply parser ───────────────────────────────────────────────
// Twilio sends the supplier's reply as 'Body' in the form body.
// We extract it and decide the reorder status.

const body = $input.first().json.body;
const raw = (body.Body || '').trim();

// Retrieve the reorder ref from the incoming message or a prior mapping
// (Twilio echoes back the conversation context via 'WaId' or correlates
//  via session — for simplicity we store reorder_id in n8n static data).
const n8nConvId = body.WaId || body.From || 'unknown';

let status = 'PROCESSING';
let confirmedItems = null;
let notes = null;

if (raw === '1') {
  status = 'CONFIRMED';
} else if (raw === '2') {
  status = 'REJECTED';
} else if (raw.startsWith('3')) {
  // Parse "3, 1=20, 2=40" format
  const overrides = {};
  const matches = [...raw.matchAll(/(\d+)\s*=\s*(\d+)/g)];
  for (const m of matches) {
    overrides[parseInt(m[1])] = parseInt(m[2]);
  }
  // Build confirmed_items — actual items will be merged by the backend
  confirmedItems = Object.entries(overrides).map(([idx, qty]) => ({
    item_index: parseInt(idx),
    confirmed_qty: qty
  }));
  status = 'PARTIALLY_CONFIRMED';
} else {
  notes = `Could not auto-parse: ${raw}`;
}

return [{
  json: {
    status,
    confirmed_items: confirmedItems,
    supplier_response: raw,
    n8n_conversation_id: n8nConvId,
    provider_message_id: body.MessageSid || null,
    notes,
    // Pass through the callback config stored in n8n workflow static data
    callback_url: $getWorkflowStaticData('node').callbackUrl,
    callback_secret: $getWorkflowStaticData('node').callbackSecret,
    reorder_id: $getWorkflowStaticData('node').reorderId,
  }
}];

// Log the failure for manual review
const data = $input.first().json;
console.error('[Reorder Callback Failed]', JSON.stringify(data));
return [{ json: { logged: true, data } }];

// Store outbound context in workflow static data so the inbound node
// can retrieve it when the supplier replies.
const data = $input.first().json;
const staticData = $getWorkflowStaticData('node');
staticData.reorderId = data.reorder_id;
staticData.callbackUrl = data.callback_url;
staticData.callbackSecret = data.callback_secret;
return $input.all();
